// Recebe: { projeto_id, titulo, segmento, atributos: [{chave, valor}] }
const body = $input.first().json.body ?? $input.first().json;

const projeto_id = body.projeto_id;
const titulo     = body.titulo ?? '';
const segmento   = body.segmento ?? 'geral';
const atributos  = Array.isArray(body.atributos) ? body.atributos : [];

if (!projeto_id) throw new Error('projeto_id ausente');

// Monta texto_base: formato determinístico para consistência de embeddings
const attrs = atributos
  .filter(a => a.chave && a.valor)
  .sort((a, b) => a.chave.localeCompare(b.chave))
  .map(a => `${a.chave}=${a.valor}`)
  .join(', ');

const texto_base = `${segmento}: ${titulo}${attrs ? '. ' + attrs : ''}`;

// Hash simples do conteúdo (para detectar mudanças sem chamar API)
const crypto = require('crypto');
const conteudo_hash = crypto.createHash('md5').update(texto_base).digest('hex');

return [{ json: { projeto_id, texto_base, conteudo_hash } }];

const geminiRes  = $input.first().json;
const preparado  = $('Preparar Texto').first().json;

const values = geminiRes?.embedding?.values;
if (!values || !Array.isArray(values) || values.length !== 768) {
  throw new Error(`Gemini retornou embedding inválido: ${JSON.stringify(geminiRes).slice(0, 200)}`);
}

// pgvector aceita string no formato "[f1,f2,...,fn]"
const embeddingStr = '[' + values.join(',') + ']';

return [{ json: {
  projeto_id:    preparado.projeto_id,
  embedding:     embeddingStr,
  modelo:        'text-embedding-004-768',
  texto_base:    preparado.texto_base,
  conteudo_hash: preparado.conteudo_hash,
  status:        'valido',
  gerado_em:     new Date().toISOString(),
  updated_at:    new Date().toISOString()
}}];
